#include<bits/stdc++.h>
using namespace std;
const int N=410,M=80010;
struct edge
{
    int to,flow,nxt;
}e[M];
int tot=1,head[N],now[N],d[N];
int s,t;
void add1(int u,int v,int w)
{
    e[++tot]=(edge){v,w,head[u]};
    head[u]=tot;
}
void add(int u,int v,int w)
{
    add1(u,v,w);
    add1(v,u,0);
}
bool bfs()
{
    queue<int> q;
    q.push(s);
    memset(d,0,sizeof(d));
    d[s]=1;
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        for(int i=head[t];i;i=e[i].nxt)
        {
            int v=e[i].to,flow=e[i].flow;
            if(flow&&!d[v])
            {
                d[v]=d[t]+1;
                if(v==(::t))
                {
                    return true;
                }
                q.push(v);
            }
        }
    }
    return false;
}
int dfs(int x,int flow)
{
    if(x==t||flow==0)
    {
        return flow;
    }
    int sum=0;
    for(int i=now[x];i;i=e[i].nxt)
    {
        now[x]=i;
        int v=e[i].to,val=e[i].flow;
        if(val&&d[v]==d[x]+1)
        {
            int tmp=min(flow,dfs(v,val));
            e[i].flow-=tmp;
            e[i^1].flow+=tmp;
            flow-=tmp;
            sum+=tmp;
            if(flow==0)
            {
                break;
            }
        }
    }
    if(sum==0)
    {
        d[x]=0;
    }
    return sum;
}
int dinic()
{
    int ans=0;
    while(bfs())
    {
        memcpy(now,head,sizeof(now));
        ans+=dfs(s,2e9);
    }
    return ans;
}
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    s=n+m+1,t=n+m+2;
    for(int i=1;i<=n;i++)
    {
        add(s,i,1);
        int c;
        scanf("%d",&c);
        for(int j=1;j<=c;j++)
        {
            int x;
            scanf("%d",&x);
            add(i,x+n,1);
        }
    }
    for(int i=1;i<=m;i++)
    {
        add(i+n,t,1);
    }
    printf("%d",dinic());
    return 0;
}
